package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.nio.charset.StandardCharsets;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    @Test
    void parse_InputStreamCharsetFormat_ShouldReturnCSVParser() throws IOException {
        // Arrange
        String csvContent = "header1,header2\nvalue1,value2\n";
        InputStream inputStream = new ByteArrayInputStream(csvContent.getBytes(StandardCharsets.UTF_8));
        Charset charset = StandardCharsets.UTF_8;
        CSVFormat format = mock(CSVFormat.class);

        // Mock Assertions.notNull to do nothing (assumed static method)
        try (MockedStatic<Assertions> assertionsMock = Mockito.mockStatic(Assertions.class)) {
            assertionsMock.when(() -> Assertions.notNull(any(), anyString())).thenAnswer(invocation -> null);

            // Mock CSVParser.parse(Reader, CSVFormat) static method to call real method
            try (MockedStatic<CSVParser> parserMock = Mockito.mockStatic(CSVParser.class, Mockito.CALLS_REAL_METHODS)) {
                // Act
                CSVParser parser = CSVParser.parse(inputStream, charset, format);

                // Assert
                assertNotNull(parser);
                assertEquals(format, parser.format);
            }
        }
    }

    @Test
    void parse_InputStreamNullInputStream_ShouldThrowNullPointerException() {
        Charset charset = StandardCharsets.UTF_8;
        CSVFormat format = mock(CSVFormat.class);

        NullPointerException exception = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((InputStream) null, charset, format);
        });
        assertTrue(exception.getMessage().contains("inputStream"));
    }

    @Test
    void parse_InputStreamNullFormat_ShouldThrowNullPointerException() {
        String csvContent = "header1,header2\nvalue1,value2\n";
        InputStream inputStream = new ByteArrayInputStream(csvContent.getBytes(StandardCharsets.UTF_8));
        Charset charset = StandardCharsets.UTF_8;

        NullPointerException exception = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(inputStream, charset, null);
        });
        assertTrue(exception.getMessage().contains("format"));
    }
}
